INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-01191', 'social-worker', 'social-worker-moex-110-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '社會工作組織在從事各種助人服務時，須有效率及效能，因此「領導」與「管理」是十分重要的。 WarrenBennis針對領導者與管理者之差異，下列敘述何者錯誤？', '["管理者即為執行者，關注系統與結構、控制流程", "管理者總是問怎麼做及何時做", "領導者即為改革者，展望未來、創造並挑戰現實", "領導者重視把事做對，管理者強調做對的事"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "5eb261e734f1", "answer_pdf_sha1": "0af20b0ec580", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01192', 'social-worker', 'social-worker-moex-110-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在管理能力方面，成功的管理者必須具備一些基本技巧，「以領導、激勵與溝通來達成組織或部門 的目標」屬於下列何種管理技巧？', '["概念能力", "人際關係能力", "技術能力", "政治能力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "5eb261e734f1", "answer_pdf_sha1": "0af20b0ec580", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01193', 'social-worker', 'social-worker-moex-110-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '「目標–路徑」理論著重於領導者如何影響部屬對於工作目標與如何達成此目標之路徑的知覺，將 領導行為區分為四類，下列何者是「指導型領導」的特徵？', '["管理者積極尋求部屬意見，並將其意見納入決策", "管理者是任務取向領導", "管理者引領部屬發揮最大潛能，獎勵達標之部屬", "領導者關心部屬福祉並公平對待每位員工"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "5eb261e734f1", "answer_pdf_sha1": "0af20b0ec580", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01194', 'social-worker', 'social-worker-moex-110-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '組織結構界定了組織成員間的分工架構與合作關係，可由複雜性、正式化以及集中化三構面描述， 下列敘述何者錯誤？', '["複雜性指組織分化的情形，可分為水平分化與垂直分化", "正式化指組織仰賴規則、正式訓練的標準化程度", "集中化係指決策權之所在", "正式化程度越高，給員工的自由裁量權就愈多"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "5eb261e734f1", "answer_pdf_sha1": "0af20b0ec580", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01195', 'social-worker', 'social-worker-moex-110-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '轉換型領導者除展現領導者對追隨者的關心外，更以發展體恤面的方式來影響追隨者，具有「4Is」 的作為，下列關於「4Is」的敘述何者錯誤？', '["個人的魅力（Individualcharisma）", "知識的啟發（Intellectualstimulation）", "鼓舞的動機（Inspirationalmotivation）", "理想化的影響（Idealizedinfluence）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "5eb261e734f1", "answer_pdf_sha1": "0af20b0ec580", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01196', 'social-worker', 'social-worker-moex-110-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '「卡內基決策模式」是一種滿意模式，也是一種有限理性的決策模式，下列何者為卡內基決策模 式之假設？', '["資訊是完全的", "決策不受決策者的偏好和價值觀影響", "由組織中結盟間的相互妥協及協商所選出有限範圍的方案", "管理者具備充分的知識、才智及充裕的時間"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "5eb261e734f1", "answer_pdf_sha1": "0af20b0ec580", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01197', 'social-worker', 'social-worker-moex-110-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '關於理性系統模式之敘述，下列何者錯誤？', '["1900年代理性系統模式興起，又可稱為科學管理學派", "理性系統模式之核心主張是：確立目標、正式化、階層化、法制化", "行政管理與科層管理屬於理性系統模式", "權變理論屬於理性系統模式"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "5eb261e734f1", "answer_pdf_sha1": "0af20b0ec580", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01198', 'social-worker', 'social-worker-moex-110-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '下列何種管理學派將組織視為有機體，把各項管理業務看成是相互聯繫的網絡，並重視組織結構 和模式的分析？', '["經驗主義學派", "系統學派", "管理過程學派", "計量理論學派"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "5eb261e734f1", "answer_pdf_sha1": "0af20b0ec580", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01199', 'social-worker', 'social-worker-moex-110-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '知識管理係指在組織中建構一個知識系統，而知識可以分為外顯知識與內隱知識，下列敘述何者正確？', '["公司內部的操作手冊、訓練手冊等書面資料屬於內隱知識", "「融合」係指將內隱知識轉換為外顯知識，亦即把內隱知識表達出來的過程", "員工個人的見解、直覺、預感屬於外顯知識", "「社會化」係指將內隱知識轉換為內隱知識，藉由共同經驗來產生新的內隱知識"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "5eb261e734f1", "answer_pdf_sha1": "0af20b0ec580", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01200', 'social-worker', 'social-worker-moex-110-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '有關1990年代以前，公共部門管理新模式已出現於多數先進國家，且以多種不同的名詞出現，下 列名詞何者是不一致的？', '["管理主義", "新公共管理", "影子政府", "企業型政府"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "5eb261e734f1", "answer_pdf_sha1": "0af20b0ec580", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
